fn solve(n: i64, k: i64) -> i64 {
    if k == 0 {
        return 1;
    }

    const MAX_VALUE: usize = 60;
    let k_minus_one = (k - 1) as usize;

    let mut depth = [0; 61];
    depth[1] = 0;
    for i in 2..=MAX_VALUE {
        let ones = (i as u64).count_ones() as usize;
        depth[i] = 1 + depth[ones];
    }

    let mut in_a = [false; 51];
    for i in 1..=MAX_VALUE {
        if depth[i] == k_minus_one {
            if i < in_a.len() {
                in_a[i] = true;
            }
        }
    }

    let bin = format!("{:b}", n);
    let mut dp_tight = [0; 51];
    let mut dp_loose = [0; 51];
    dp_tight[0] = 1;

    for c in bin.chars() {
        let bit = if c == '1' { 1 } else { 0 };
        let mut next_tight = [0; 51];
        let mut next_loose = [0; 51];

        for ones in 0..51 {
            if dp_tight[ones] != 0 {
                for d in 0..=bit {
                    let new_ones = ones + if d == 1 { 1 } else { 0 };
                    if new_ones <= 50 {
                        if d < bit {
                            next_loose[new_ones] += dp_tight[ones];
                        } else {
                            next_tight[new_ones] += dp_tight[ones];
                        }
                    }
                }
            }
            if dp_loose[ones] != 0 {
                for d in 0..=1 {
                    let new_ones = ones + if d == 1 { 1 } else { 0 };
                    if new_ones <= 50 {
                        next_loose[new_ones] += dp_loose[ones];
                    }
                }
            }
        }

        dp_tight = next_tight;
        dp_loose = next_loose;
    }

    let mut total_count: i64 = 0;
    for ones in 0..51 {
        if in_a[ones] {
            total_count += dp_tight[ones];
            total_count += dp_loose[ones];
        }
    }

    if k == 1 {
        total_count = if total_count > 0 { total_count - 1 } else { 0 };
    }

    total_count
}
